public class LinearSearch {
    public static int search(int[] arr, int target) {
        // Input: Unsorted array 'arr' and value 'target'

        // Process: Sequential loop comparison
        for (int i = 0; i < arr.length; i++) {
            if (arr[i] == target) {
                // Output: Return index if found
                return i;
            }
        }

        // Output: Return -1 if not found
        return -1;
    }
}

