public class BinarySearch {
    public static int search(int[] arr, int target) {
        // Input: Sorted array 'arr' and search 'target'

        // Storage: Pointer variables
        int low = 0;
        int high = arr.length - 1;

        // Process: Binary halving algorithm
        while (low <= high) {
            int mid = low + (high - low) / 2; // Midpoint division

            if (arr[mid] == target) {
                return mid; // Output: Index found
            } else if (arr[mid] < target) {
                low = mid + 1; // Discard left half
            } else {
                high = mid - 1; // Discard right half
            }
        }

        return -1; // Output: Not found
    } 
}

