public class UniformBinarySearch {
    public static int search(int[] arr, int target, int[] delta) {
        // Input: Sorted array, target, and precomputed delta lookup table

        // Storage: Pointer state
        int i = delta[0] - 1; // Initial index midpoint
        int d = 0;            // Step counter
        int n = arr.length;

        // Process: Uniform lookup stepping
        while (true) {
            if (i < 0 || i >= n) return -1; // Boundary check

            if (target == arr[i]) {
                return i; // Output: Found
            } else if (delta[d] == 0) {
                break; // Search exhausted
            } else {
                if (target < arr[i]) {
                    i -= delta[++d];
                } else {
                    i += delta[++d];
                }
            }
        }
        return -1; // Output: Not found
    }
}

public class InterpolationSearch {
    public static int search(int[] arr, int target) {
        // Input: Sorted array and target

        // Storage: Bounds pointers
        int low = 0;
        int high = arr.length - 1;

        // Process: Probing loops
        while (low <= high && target >= arr[low] && target <= arr[high]) {
            if (low == high) {
                if (arr[low] == target) return low; // Output
                return -1;
            }

            // Linear interpolation probing formula
            int pos = low + (int)(((double)(high - low) / (arr[high] - arr[low])) * (target - arr[low]));

            if (arr[pos] == target) {
                return pos; // Output: Match
            }
            if (arr[pos] < target) {
                low = pos + 1; // Recurse right
            } else {
                high = pos - 1; // Recurse left
            }
        }
        return -1; // Output: Failure
    }
}

