public class FibonacciSearch {
    public static int search(int[] arr, int target) {
        // Input: Sorted array and target
        int n = arr.length; // Storage

        // Storage: Initialize Fibonacci numbers
        int fibM2 = 0; // (m-2)th fib
        int fibM1 = 1; // (m-1)th fib
        int fibM = fibM2 + fibM1; // mth fib

        while (fibM < n) {
            fibM2 = fibM1;
            fibM1 = fibM;
            fibM = fibM2 + fibM1;
        }

        int offset = -1; // Storage

        // Process: Fibonacci range check
        while (fibM > 1) {
            int i = Math.min(offset + fibM2, n - 1); // Storage: Probe index

            if (arr[i] < target) {
                fibM = fibM1;
                fibM1 = fibM2;
                fibM2 = fibM - fibM1;
                offset = i;
            } else if (arr[i] > target) {
                fibM = fibM2;
                fibM1 = fibM1 - fibM2;
                fibM2 = fibM - fibM1;
            } else {
                return i; // Output: Match found
            }
        }

        if (fibM1 == 1 && arr[offset + 1] == target) {
            return offset + 1; // Output: Boundary check match
        }

        return -1; // Output: Failure
    }
}
